import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { 
  theme, Row, Col, Card, Table, Button, Space, Typography, 
  Input, Breadcrumb, Tag, Modal, Form, Divider, App, Flex, Empty
} from "antd";
import { 
  HomeOutlined, SearchOutlined, PlusOutlined, 
  EditOutlined, DeleteOutlined, PaperClipOutlined,
  UserOutlined, CalendarOutlined,
  DownloadOutlined, MessageOutlined, CloseOutlined
} from "@ant-design/icons";
import dayjs from "dayjs";

const { useToken } = theme;
const { Title, Text } = Typography;

interface NoticeComment { id: string; author: string; content: string; date: string; }
interface NoticeItem {
  key: string;
  no: string;
  title: string;
  content: string;
  isNotice: boolean;
  author: string;
  authorId: string;
  date: string;
  hasFile: boolean;
  files?: string[];
  comments?: NoticeComment[];
}

const initialNotices: NoticeItem[] = [
  { 
    key: "1", no: "공지", title: "[공지] 라벨링 및 검수시 가이드라인을 참고해주세요.", isNotice: true, author: "관리자", authorId: "tai", date: "2023-07-28 10:07", hasFile: true,
    content: "안녕하세요. 라벨링 작업 시 다음 가이드라인을 반드시 숙지해 주시기 바랍니다. 규정에 맞지 않는 데이터는 검수 반려 처리가 될 수 있습니다.",
    files: ["가이드라인_3IF_v1.1.1.hwp"],
    comments: [
      { id: "c1", author: "tai", content: "넵", date: "2023-07-28 15:07" },
      { id: "c2", author: "user007", content: "네", date: "2023-07-28 15:07" }
    ]
  },
  { key: "2", no: "공지", title: "[공지] 실적관련", isNotice: true, author: "관리자", authorId: "admin", date: "2023-07-27 15:07", hasFile: true, content: "실적 관리 규정이 변경되었습니다.", files: ["실적규정.pdf"] },
  { key: "3", no: "93", title: "BGM 공유", isNotice: false, author: "관리자", authorId: "admin", date: "2023-07-27 15:07", hasFile: true, content: "업무 시 사용할 수 있는 BGM 리스트입니다." },
  { key: "4", no: "92", title: "시스템 점검 안내", isNotice: false, author: "운영자", authorId: "op01", date: "2023-07-26 09:30", hasFile: false, content: "내일 새벽 시스템 점검이 있습니다." },
];

export default function NoticePage() {
  const { token } = useToken();
  const { t } = useTranslation(["board", "common"]);
  const { message } = App.useApp();

  const [notices, setNotices] = useState<NoticeItem[]>(initialNotices);
  const [selectedRowKeys, setSelectedRowKeys] = useState<React.Key[]>([]);
  const [isWriteModalOpen, setIsWriteModalOpen] = useState(false);
  const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<NoticeItem | null>(null);
  const [selectedItem, setSelectedItem] = useState<NoticeItem | null>(null);
  const [commentText, setCommentText] = useState("");
  const [form] = Form.useForm();

  const handleAdd = () => {
    setEditingItem(null);
    form.resetFields();
    setIsWriteModalOpen(true);
  };

  const handleEdit = () => {
    const target = notices.find(n => selectedRowKeys.includes(n.key));
    if (target) {
      setEditingItem(target);
      form.setFieldsValue(target);
      setIsWriteModalOpen(true);
    }
  };

  const handleSave = (values: any) => {
    if (editingItem) {
      setNotices(notices.map(n => n.key === editingItem.key ? { ...n, ...values } : n));
    } else {
      const newItem: NoticeItem = {
        key: Date.now().toString(),
        no: (notices.length + 90).toString(),
        ...values,
        date: dayjs().format("YYYY-MM-DD HH:mm"),
        isNotice: false,
        hasFile: false,
        author: "관리자",
        authorId: "admin"
      };
      setNotices([newItem, ...notices]);
    }
    setIsWriteModalOpen(false);
    message.success(t("save", { ns: "common" }));
  };

  const handleRowClick = (record: NoticeItem) => {
    setSelectedItem(record);
    setIsDetailModalOpen(true);
  };

  const handleAddComment = () => {
    if (!commentText.trim() || !selectedItem) return;
    const newComment: NoticeComment = {
      id: Date.now().toString(),
      author: "me",
      content: commentText,
      date: dayjs().format("YYYY-MM-DD HH:mm")
    };
    const updatedItem = {
      ...selectedItem,
      comments: [...(selectedItem.comments || []), newComment]
    };
    setNotices(notices.map(n => n.key === selectedItem.key ? updatedItem : n));
    setSelectedItem(updatedItem);
    setCommentText("");
    message.success(t("save", { ns: "common" }));
  };

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
        <div>
          <Title level={4} style={{ margin: 0 }}>{t("title")}</Title>
        </div>
        <Breadcrumb 
          items={[
            { title: <Space><HomeOutlined /> {t("listPage.home", { ns: "labeling" })}</Space> },
            { title: t("title") }
          ]} 
        />
      </div>

      <Card 
        variant="borderless" 
        style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary }}
        styles={{ body: { padding: "0 12px 12px 12px" } }}
      >
        <div style={{ padding: "16px 4px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <Text strong>{t("category.all")}</Text>
          <Space>
            <Button size="small" icon={<SearchOutlined />}>{t("search", { ns: "common" })}</Button>
            <Button size="small" icon={<PlusOutlined />} onClick={handleAdd}>{t("write")}</Button>
            <Button size="small" icon={<EditOutlined />} disabled={selectedRowKeys.length !== 1} onClick={handleEdit}>{t("edit", { ns: "common" })}</Button>
            <Button size="small" icon={<DeleteOutlined />} disabled={selectedRowKeys.length === 0} danger>{t("delete", { ns: "common" })}</Button>
          </Space>
        </div>

        <Table 
          rowSelection={{
            type: "checkbox",
            selectedRowKeys,
            onChange: setSelectedRowKeys
          }}
          dataSource={notices}
          size="small"
          pagination={{ pageSize: 10, size: "small" }}
          onRow={(record) => ({
            onClick: (e) => {
              if (e.target instanceof HTMLInputElement || (e.target as HTMLElement).closest('.ant-checkbox-wrapper')) return;
              handleRowClick(record);
            },
            style: { cursor: "pointer" }
          })}
          columns={[
            { 
              title: t("columns.no"), 
              dataIndex: "no", 
              key: "no", 
              width: 80, 
              align: "center",
              render: (v, r) => r.isNotice ? <Tag color="error" style={{ margin: 0 }}>{t("category.notice")}</Tag> : v
            },
            { 
              title: t("columns.subject"), 
              dataIndex: "title", 
              key: "title",
              render: (v, r) => <Text strong={r.isNotice}>{v}</Text>
            },
            { 
              title: t("common.file", { ns: "common", defaultValue: "File" }), 
              dataIndex: "hasFile", 
              key: "file", 
              align: "center", 
              width: 80,
              render: (v) => v ? <PaperClipOutlined style={{ color: token.colorTextSecondary }} /> : "-"
            },
            { title: t("columns.author"), dataIndex: "author", key: "author", align: "center", width: 120 },
            { title: t("columns.date"), dataIndex: "date", key: "date", align: "center", width: 180 },
          ]}
        />
      </Card>

      <Modal
        title={<Title level={5} style={{ margin: 0 }}>{t("category.notice")}</Title>}
        open={isDetailModalOpen}
        onCancel={() => setIsDetailModalOpen(false)}
        width={800}
        footer={null}
        closeIcon={<CloseOutlined />}
        centered
        styles={{ body: { padding: "0 24px 24px 24px", minHeight: 400 } }}
      >
        {selectedItem && (
          <div style={{ marginTop: 20 }}>
            <Title level={4}>{selectedItem.title}</Title>
            <Space size={16} style={{ marginBottom: 20 }}>
              <Space><UserOutlined style={{ color: token.colorTextSecondary }} /> <Text>{selectedItem.author}({selectedItem.authorId})</Text></Space>
              <Space><CalendarOutlined style={{ color: token.colorTextSecondary }} /> <Text>{selectedItem.date}</Text></Space>
            </Space>
            <Divider style={{ margin: "12px 0" }} />

            <div style={{ padding: "10px 0", minHeight: 120, fontSize: 15 }}>
              {selectedItem.content}
            </div>

            {selectedItem.hasFile && (
              <div style={{ marginTop: 24, padding: "12px 16px", background: token.colorFillAlter, borderRadius: 8 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
                  <Space><PaperClipOutlined /> <Text strong>{t("common.attachment", { ns: "common", defaultValue: "Attachments" })}</Text></Space>
                  <Button size="small" icon={<DownloadOutlined />}>{t("common.downloadAll", { ns: "common", defaultValue: "Download All" })}</Button>
                </div>
                <div style={{ background: token.colorBgContainer, padding: "8px 12px", borderRadius: 4, display: "flex", justifyContent: "flex-end" }}>
                  <Text style={{ color: token.colorPrimary, cursor: "pointer", textDecoration: "underline" }}>
                    {selectedItem.files?.[0]}
                  </Text>
                </div>
              </div>
            )}

            <div style={{ marginTop: 32 }}>
              <Space style={{ marginBottom: 16 }}><MessageOutlined /> <Text strong>{t("common.comment", { ns: "common", defaultValue: "Comments" })}</Text></Space>
              
              <div style={{ display: "flex", gap: 8, marginBottom: 20 }}>
                <Input.TextArea 
                  rows={2} 
                  autoSize={{ minRows: 2, maxRows: 4 }}
                  placeholder={t("common.commentPlaceholder", { ns: "common", defaultValue: "Enter a comment..." })} 
                  style={{ background: token.colorFillAlter, border: "none" }}
                  value={commentText}
                  onChange={(e) => setCommentText(e.target.value)}
                />
                <Button 
                  type="primary" 
                  style={{ height: "auto", padding: "0 24px" }}
                  onClick={handleAddComment}
                >
                  {t("add", { ns: "common" })}
                </Button>
              </div>

              <Flex vertical style={{ marginTop: 16 }}>
                {(selectedItem.comments || []).length > 0 ? (
                  (selectedItem.comments || []).map((c) => (
                    <div key={c.id} style={{ padding: "12px 0", borderBottom: `1px solid ${token.colorBorderSecondary}`, display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                      <div>
                        <div style={{ fontSize: 13, fontWeight: 500, marginBottom: 4 }}>{c.content}</div>
                        <Space size={16} style={{ fontSize: 11 }}>
                           <Space><UserOutlined />{c.author}</Space>
                           <Space><CalendarOutlined />{c.date}</Space>
                        </Space>
                      </div>
                      <Button type="text" danger icon={<DeleteOutlined />} size="small" />
                    </div>
                  ))
                ) : (
                  <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description={t("noObjects", { ns: "common" })} />
                )}
              </Flex>
            </div>
          </div>
        )}
      </Modal>

      <Modal 
        title={editingItem ? t("edit", { ns: "common" }) : t("add", { ns: "common" })} 
        open={isWriteModalOpen} 
        onCancel={() => setIsWriteModalOpen(false)}
        onOk={() => form.submit()}
        centered
        destroyOnHidden
      >
        <Form form={form} layout="vertical" onFinish={handleSave} style={{ marginTop: 20 }}>
          <Form.Item name="title" label={t("columns.subject")} rules={[{ required: true }]}><Input /></Form.Item>
          <Form.Item name="content" label={t("common.content", { ns: "common", defaultValue: "Content" })} initialValue=""><Input.TextArea rows={6} /></Form.Item>
        </Form>
      </Modal>
    </div>
  );
}
